#!/usr/bin/env node
// Squad Self-Check — validates squad integrity
// Generated by snap-squad for "The Default Squad"
// Run: node .squad/eval.mjs

import { readFileSync, existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '..');
const agents = ["architect","coder","tester","devrel","prompter","gitops","evaluator","researcher","scribe"];
const routes = [{"agent":"architect","pattern":"architecture"},{"agent":"coder","pattern":"implementation"},{"agent":"tester","pattern":"testing"},{"agent":"devrel","pattern":"documentation"},{"agent":"prompter","pattern":"prompts"},{"agent":"gitops","pattern":"git"},{"agent":"evaluator","pattern":"evals"},{"agent":"researcher","pattern":"research"},{"agent":"scribe","pattern":"history"}];

let pass = 0, fail = 0;
const fails = [];
const g = (s) => `\x1b[32m${s}\x1b[0m`;
const r = (s) => `\x1b[31m${s}\x1b[0m`;
const b = (s) => `\x1b[1m${s}\x1b[0m`;
const d = (s) => `\x1b[2m${s}\x1b[0m`;

function check(name, ok) {
  if (ok) { pass++; console.log(g(`  ✅ ${name}`)); }
  else { fail++; fails.push(name); console.log(r(`  ❌ ${name}`)); }
}

function has(p) { return existsSync(join(root, p)); }

function read(p) {
  const f = join(root, p);
  return existsSync(f) ? readFileSync(f, 'utf-8') : '';
}

function fileCheck(p, label) { check(label || p, has(p)); }

function contentCheck(p, pattern, label) { check(label, pattern.test(read(p))); }

console.log(`\n${b('  Squad Self-Check — The Default Squad')}\n`);

// ── Files ──
console.log(d('  File Existence'));
for (const f of ['AGENTS.md', 'CLAUDE.md', '.github/copilot-instructions.md', 'JOURNAL.md',
  '.squad/team.md', '.squad/routing.md', '.squad/decisions.md']) fileCheck(f);
for (const a of agents) fileCheck(`.squad/agents/${a}/charter.md`);

// ── Hook Chain ──
console.log(d('\n  Hook Chain'));
contentCheck('AGENTS.md', /\*\*\[/, 'role-tag format in AGENTS.md');
contentCheck('AGENTS.md', /always.on duties/i, 'Always-On Duties in AGENTS.md');
contentCheck('AGENTS.md', /before you say.*done/i, 'completion gate in AGENTS.md');
contentCheck('AGENTS.md', /task.*tool|mode.*background/i, 'dispatch instructions in AGENTS.md');
contentCheck('CLAUDE.md', /session.*start|session.*protocol/i, 'Session Start in CLAUDE.md');
contentCheck('CLAUDE.md', /completion.*gate|before.*ending/i, 'Completion Gate in CLAUDE.md');
contentCheck('.github/copilot-instructions.md', /proactive.*quality|quality.*trigger/i, 'Quality Triggers in copilot-instructions');

// ── Routing ──
console.log(d('\n  Routing'));
contentCheck('.squad/routing.md', /work type.*agent/i, 'routing table exists');
contentCheck('.squad/routing.md', /automatic secondary/i, 'secondary routing triggers');
const routing = read('.squad/routing.md');
for (const { agent } of routes) {
  check(`routing.md references ${agent}`, new RegExp(agent, 'i').test(routing));
}

// ── Charters ──
console.log(d('\n  Charter Quality'));
for (const a of agents) {
  const c = read(`.squad/agents/${a}/charter.md`);
  check(`${a}: Identity section`, /## Identity/.test(c));
  check(`${a}: How I Work section`, /## How I Work/.test(c));
  check(`${a}: Voice section`, /## Voice/.test(c));
}

// ── Summary ──
const total = pass + fail;
const rate = total > 0 ? ((pass / total) * 100).toFixed(0) : '0';
const icon = fail === 0 ? g('PASS ✅') : r('FAIL ❌');
console.log(`\n${b(`  ${pass}/${total} checks (${rate}%) — ${icon}`)}\n`);
if (fails.length) {
  console.log(r('  Failed:'));
  for (const f of fails) console.log(r(`    - ${f}`));
  console.log('');
}
process.exit(fail > 0 ? 1 : 0);
